class SecureStorage(private val context: Context) {
    private val PREFS_NAME = "secure_prefs"
    private val KEY_AES = "aes_key"
    private val KEY_IV = "iv_key"
    
    private val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
    
    fun encrypt(data: String): String {
        try {
            val cipher = Cipher.getInstance("AES/CBC/PKCS5Padding")
            val key = generateKey()
            cipher.init(Cipher.ENCRYPT_MODE, key)
            
            val encrypted = cipher.doFinal(data.toByteArray())
            val iv = cipher.iv
            
            prefs.edit()
                .putString(KEY_IV, iv.joinToString(",") { it.toString() })
                .apply()
                
            return encrypted.joinToString(",") { it.toString() }
        } catch (e: Exception) {
            Log.e("SecureStorage", "Encryption failed", e)
            return ""
        }
    }
    
    fun decrypt(encryptedData: String): String {
        try {
            val cipher = Cipher.getInstance("AES/CBC/PKCS5Padding")
            val key = generateKey()
            
            val ivArray = prefs.getString(KEY_IV, "")?.split(",")?.map { it.toByte() }?.toByteArray()
            val iv = ivArray ?: ByteArray(16) { 0 }
            
            cipher.init(Cipher.DECRYPT_MODE, key, android.util.Base64.decode(iv, 0))
            
            val decrypted = cipher.doFinal(encryptedData.split(",").map { it.toByte() }.toByteArray())
            return String(decrypted)
        } catch (e: Exception) {
            Log.e("SecureStorage", "Decryption failed", e)
            return ""
        }
    }
    
    fun savePurchaseData(productId: String, encryptedData: String) {
        prefs.edit()
            .putString("purchase_$productId", encryptedData)
            .apply()
    }
    
    fun saveTransaction(transaction: WalletTransaction) {
        prefs.edit()
            .putString("transaction_${transaction.id}", 
                "${transaction.amount}|${transaction.currency}|${transaction.timestamp}")
            .apply()
    }
    
    fun verifyPurchase(purchaseToken: String): Boolean {
        val encrypted = prefs.getString("purchase_$purchaseToken", null)
        return encrypted != null
    }
    
    private fun generateKey(): SecretKeySpec {
        val key = ByteArray(16)
        SecureRandom().nextBytes(key)
        return SecretKeySpec(key, "AES")
    }
}

